export function getAlgorithm(slug: string): Algorithm | undefined {
  return ALGORITHMS.find(a => a.slug === slug);
}

export function getAlgorithmsByCategory(category: Category): Algorithm[] {
  return ALGORITHMS.filter(a => a.category === category);
}

export function getAllSlugs(): string[] {
  return ALGORITHMS.map(a => a.slug);
}
